    double sum = 0.0;

    // Read integer n from user
    printf("Enter an integer n: ");
    scanf("%d", &n);

    // Calculate the sum of the series
    for (int i = 1; i <= n; ++i) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    // Output the result with precision
    printf("%.6f\n", sum);

    return 0;
}

