    int n;
    double sum = 0.0;

    // Read integer n from user
    printf("Enter an integer n: ");
    scanf("%d", &n);

    // Calculate the sum of the series
    for (int i = 1; i <= n; ++i) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    // Output the result with precision
    printf("%.6f\n", sum);

    return 0;
}

#include <stdio.h>

int main(void) {
    int n;

    // Read integer n from the user
    scanf("%d", &n);

    // Generate and print each row of the triangle pattern
    for (int i = 1; i <= n; ++i) {
        // Print leading spaces to center the digits
        for (int j = n - i; j > 0; --j) {
            printf(" ");
        }

        // Print the current row's digits
        for (int k = 0; k < i; ++k) {
            printf("%d", i);
        }

        // Move to the next line after each row
        printf("\n");
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

#define EPSILON 1e-9

typedef struct {
    double x;
    double y;
} Point;

double distance(Point a, Point b) {
    return sqrt((a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y));
}

double heron(double a, double b, double c) {
    double s = (a + b + c) / 2.0;
    return sqrt(s * (s - a) * (s - b) * (s - c));
}

int collinear(Point p1, Point p2, Point p3) {
    double d1 = distance(p1, p2);
    double d2 = distance(p2, p3);
    double d3 = distance(p3, p1);
    return fabs(d1 + d2 - d3) < EPSILON || fabs(d1 + d3 - d2) < EPSILON || fabs(d2 + d3 - d1) < EPSILON;
}

int main(void) {
    Point points[4];

    // Read 4 coordinate pairs
    for (int i = 0; i < 4; i++) {
        scanf("%lf %lf", &points[i].x, &points[i].y);
    }

    // Generate all 3-point combinations
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            for (int k = j + 1; k < 4; k++) {
                Point p1 = points[i];
                Point p2 = points[j];
                Point p3 = points[k];

                // Check if points are collinear
                if (!collinear(p1, p2, p3)) {
                    double a = distance(p1, p2);
                    double b = distance(p2, p3);
                    double c = distance(p3, p1);

                    // Calculate area using Heron's formula
                    double area = heron(a, b, c);

                    // Display area with 3 decimal places
                    printf("%.3f\n", area);
                }
            }
        }
    }

    return 0;
}

