#include <stdio.h>
#include <stdlib.h>

#define NUM_NUMBERS 5

int main(void) {
    int numbers[NUM_NUMBERS];
    int guessed[NUM_NUMBERS] = {0};
    int score = 0;
    char input[2];

    // Generate 5 unique random numbers (1-10)
    for (int i = 0; i < NUM_NUMBERS; i++) {
        do {
            numbers[i] = rand() % 10 + 1;
        } while (guessed[numbers[i] - 1]);
        guessed[numbers[i] - 1] = 1;
    }

    // Game loop
    for (int i = 0; i < NUM_NUMBERS; i++) {
        printf("Numbers: ");
        for (int j = 0; j < NUM_NUMBERS; j++) {
            if (guessed[j]) {
                printf("*");
            } else {
                printf("%d", numbers[j]);
            }
        }
        printf("\nPick position (1-%d): ", NUM_NUMBERS);
        scanf("%s", input);

        int position = input[0] - '0' - 1;
        if (position < 0 || position >= NUM_NUMBERS) {
            printf("Invalid position. Try again.\n");
            continue;
        }

        printf("Guess even or odd (E/O): ");
        scanf("%s", input);

        if ((input[0] == 'E' && numbers[position] % 2 == 0) ||
            (input[0] == 'O' && numbers[position] % 2 != 0)) {
            score += 5;
            guessed[position] = 1;
            printf("Correct! You win 5 points.\n");
        } else {
            printf("Wrong guess. Try again.\n");
        }

        printf("\n");
    }

    // Display final score
    printf("Final Score: %d\n", score);

    return 0;
}

